CREATE FUNCTION disable_alter_domain() RETURNS event_trigger LANGUAGE plpgsql AS $$
BEGIN
  IF tg_tag = 'ALTER DOMAIN' THEN
    RAISE EXCEPTION '% is disabled', tg_tag;
  END IF;
END;

$$;

CREATE FUNCTION test_aggregate(integer, integer) RETURNS INTEGER LANGUAGE sql AS $$
SELECT array_agg($1);

$$;

CREATE FUNCTION utf8_to_latin1(IN source_encoding_id INTEGER, IN destination_encoding_id INTEGER, IN source CSTRING, IN destination INTERNAL, IN source_length INTEGER) RETURNS TEXT LANGUAGE plpython3u AS $$
return source.encode('UTF8').decode('LATIN-1')

$$;

